changeSet.sql:
IF OBJECT_ID(N'sw.sensitive_words', N'U') IS NOT NULL
BEGIN
    IF EXISTS (
        SELECT 1
        FROM sys.indexes
        WHERE object_id = OBJECT_ID(N'sw.sensitive_words')
          AND name = N'IX_sw_words_active'
    )
    BEGIN
        DROP INDEX IX_sw_words_active ON sw.sensitive_words;
    END;

    IF EXISTS (
        SELECT 1
        FROM sys.indexes
        WHERE object_id = OBJECT_ID(N'sw.sensitive_words')
          AND name = N'UX_sw_words_active_word'
    )
    BEGIN
        DROP INDEX UX_sw_words_active_word ON sw.sensitive_words;
    END;

    IF COL_LENGTH(N'sw.sensitive_words', N'is_active') IS NOT NULL
    BEGIN
        EXEC sp_executesql N'DELETE FROM sw.sensitive_words WHERE is_active = 0';
    END;

    IF NOT EXISTS (
        SELECT 1
        FROM sys.indexes
        WHERE object_id = OBJECT_ID(N'sw.sensitive_words')
          AND name = N'UX_sw_words_normalized_word'
    )
    BEGIN
        CREATE UNIQUE INDEX UX_sw_words_normalized_word
            ON sw.sensitive_words(normalized_word);
    END;

    IF NOT EXISTS (
        SELECT 1
        FROM sys.indexes
        WHERE object_id = OBJECT_ID(N'sw.sensitive_words')
          AND name = N'IX_sw_words_severity'
    )
    BEGIN
        CREATE INDEX IX_sw_words_severity
            ON sw.sensitive_words(severity_level);
    END;

    IF COL_LENGTH(N'sw.sensitive_words', N'is_active') IS NOT NULL
    BEGIN
        DECLARE @constraintName sysname;

        SELECT @constraintName = dc.name
        FROM sys.default_constraints dc
        JOIN sys.columns c ON c.default_object_id = dc.object_id
        WHERE dc.parent_object_id = OBJECT_ID(N'sw.sensitive_words')
          AND c.name = N'is_active';

        IF @constraintName IS NOT NULL
        BEGIN
            DECLARE @dropConstraintSql nvarchar(max);
            SET @dropConstraintSql = N'ALTER TABLE sw.sensitive_words DROP CONSTRAINT ' + QUOTENAME(@constraintName);
            EXEC sp_executesql @dropConstraintSql;
        END;

        EXEC sp_executesql N'ALTER TABLE sw.sensitive_words DROP COLUMN is_active';
    END;
END;
